using System.Collections.Generic; using UnityEngine; using NabyeolDabyeolDreamPuzzle.Collection;
namespace NabyeolDabyeolDreamPuzzle.UI { public class CollectionSceneController:MonoBehaviour{ [SerializeField] CollectionManager collectionManager; [SerializeField] List<CharacterCardUI> characterCards=new List<CharacterCardUI>(); [SerializeField] bool refreshOnStart=true; void Awake(){ collectionManager??=FindAnyObjectByType<CollectionManager>(); if(characterCards.Count==0) AutoFindCardsInChildren(); } void OnEnable(){ if(collectionManager!=null) collectionManager.OnCollectionChanged+=RefreshCharacterCards; } void OnDisable(){ if(collectionManager!=null) collectionManager.OnCollectionChanged-=RefreshCharacterCards; } void Start(){ if(refreshOnStart) RefreshCharacterCards(); } public void RefreshCharacterCards(){ if(collectionManager==null){ClearAllCards(); return;} var chars=collectionManager.GetAllCharacters(); for(int i=0;i<characterCards.Count;i++){var card=characterCards[i]; if(card==null)continue; if(chars==null||i>=chars.Count||chars[i]==null){card.Clear(); continue;} card.Setup(chars[i],collectionManager.IsCharacterUnlocked(chars[i]));}} public void ClearAllCards(){ foreach(var c in characterCards) if(c)c.Clear(); } public void AutoFindCardsInChildren(){ characterCards=new List<CharacterCardUI>(GetComponentsInChildren<CharacterCardUI>(true)); } public void SetCards(List<CharacterCardUI> cards){ characterCards=cards??new List<CharacterCardUI>(); RefreshCharacterCards(); }} }
